tool_calls:
awk -F',' '
function esc(s){ gsub(/\\/,"\\\\",s); gsub(/"/,"\\\"",s); return s }
NR==1 { for(i=1;i<=NF;i++) hdr[i]=$i; ncol=NF; next }
{
  if(out!="") out=out",\n"
  rec="  {"
  for(i=1;i<=ncol;i++){
    if(i>1) rec=rec", "
    rec=rec"\"" esc(hdr[i]) "\": \"" esc($i) "\""
  }
  rec=rec"}"
  out=out rec
}
END { print "["; print out; print "]" }
' /data/users.csv

